#include <stdio.h>
#include <stdlib.h>

char arr[4][4];

int boardval(char * loc)
{
		if (*loc == '#')
				return 1;
		else return -1;
}

int main(void)
{
		for (int i = 0; i < 4; i++)
				for (int j = 0; j < 4; j++)
						scanf("%c ", &arr[i][j]);

		int sum;
		for (int i = 0; i < 3; i++)
				for (int j = 0; j < 3; j++){
						sum = 0;
						sum += (boardval(&arr[i][j]) + boardval(&arr[i+1][j]) + boardval(&arr[i][j+1]) + boardval(&arr[i+1][j+1]));
						if (abs(sum) >= 2){
								printf("YES\n");
								return 0;
						}
		}

		printf("NO\n");
		return 0;
}

