//! http://codeforces.com/contest/287/problem/A

#[macro_export]
macro_rules! scanln {
  ($($var:ident : $ty:path),+) => {
    $(let $var: $ty;)+
    {
      use std::io;
      let mut __buf = String::new();
      io::stdin().read_line(&mut __buf).unwrap();
      let mut eles = __buf.split_whitespace();
      $($var = Scan::scan(&mut eles);)+
    }
  }
}

pub trait Scan {
  fn scan<'a, I>(eles: &mut I) -> Self where I: Iterator<Item=&'a str>;
}

macro_rules! impl_scan_single {
  ($ty:ty) => {
    impl Scan for $ty {
      fn scan<'a, I>(eles: &mut I) -> Self where I: Iterator<Item=&'a str> {
        let next = eles.next().unwrap();
        match next.parse() {
          Ok(res) => res,
          Err(_) => panic!()
        }
      }
    }
  }
}

impl_scan_single!(u8);
impl_scan_single!(u16);
impl_scan_single!(u32);
impl_scan_single!(u64);
impl_scan_single!(usize);
impl_scan_single!(i8);
impl_scan_single!(i16);
impl_scan_single!(i32);
impl_scan_single!(i64);
impl_scan_single!(f32);
impl_scan_single!(f64);
impl_scan_single!(isize);
impl_scan_single!(String);

const __IMPL_SCAN_FOR_VEC: () = {
  use std::str::FromStr;
  impl<T> Scan for Vec<T> where T: FromStr {
    fn scan<'a, I>(eles: &mut I) -> Self where I: Iterator<Item=&'a str> {
      eles.map(|str| match str.parse() {
        Ok(res) => res,
        Err(_) => panic!()
      }).collect()
    }
  }
};

/// Stores elements in row-major order.
pub struct Matrix<T> {
  pub elements: Vec<T>,
  pub width: usize
}

impl<T> Matrix<T> {
  pub fn row_major_index(&self, idx: (usize, usize)) -> usize {
    let (x, y) = idx;
    y * self.width + x
  }

  pub fn get(&self, idx: (usize, usize)) -> Option<&T> {
    let index = self.row_major_index(idx);
    if index < self.elements.len() {
      Some(&self.elements[index])
    } else {
      None
    }
  }

  pub fn get_mut(&mut self, idx: (usize, usize)) -> Option<&mut T> {
    let index = self.row_major_index(idx);
    if index < self.elements.len() {
      Some(&mut self.elements[index])
    } else {
      None
    }
  }
}

impl<T> Matrix<T> where T: Default + Clone {
  pub fn new(width: usize, height: usize) -> Self {
    Matrix {
      elements: vec![T::default(); width * height],
      width: width
    }
  }
}

impl<T> Matrix<T> where T: Clone {
  pub fn with_default(width: usize, height: usize, default: T) -> Self {
    Matrix {
      elements: vec![default; width * height],
      width: width
    }
  }
}

const __IMPL_INDEX_FOR_MATRIX: () = {
  use std::ops::{Index, IndexMut};

  impl<T> Index<(usize, usize)> for Matrix<T> {
    type Output = T;
    fn index(&self, idx: (usize, usize)) -> &Self::Output {
      self.get(idx).unwrap()
    }
  }

  impl<T> IndexMut<(usize, usize)> for Matrix<T> {
    fn index_mut(&mut self, idx: (usize, usize)) -> &mut Self::Output {
      self.get_mut(idx).unwrap()
    }
  }
};

